package logger

import (
	"encoding/json"
	"fmt"
	"io"
	"os"
	"time"
)

type Level int

const (
	DEBUG Level = iota
	INFO
	WARN
	ERROR
)

var levelNames = map[Level]string{
	DEBUG: "DEBUG",
	INFO:  "INFO",
	WARN:  "WARN",
	ERROR: "ERROR",
}

type Logger struct {
	level  Level
	output io.Writer
}

func New(level Level) *Logger {
	return &Logger{level: level, output: os.Stderr}
}

func (l *Logger) SetOutput(w io.Writer) {
	l.output = w
}

func (l *Logger) log(level Level, msg string, fields map[string]interface{}) {
	if level < l.level {
		return
	}
	entry := map[string]interface{}{
		"timestamp": time.Now().Format(time.RFC3339),
		"level":     levelNames[level],
		"message":   msg,
	}
	for k, v := range fields {
		entry[k] = v
	}
	data, _ := json.Marshal(entry)
	fmt.Fprintln(l.output, string(data))
}

func (l *Logger) Debug(msg string, fields ...map[string]interface{}) {
	f := mergeFields(fields)
	l.log(DEBUG, msg, f)
}

func (l *Logger) Info(msg string, fields ...map[string]interface{}) {
	f := mergeFields(fields)
	l.log(INFO, msg, f)
}

func (l *Logger) Warn(msg string, fields ...map[string]interface{}) {
	f := mergeFields(fields)
	l.log(WARN, msg, f)
}

func (l *Logger) Error(msg string, fields ...map[string]interface{}) {
	f := mergeFields(fields)
	l.log(ERROR, msg, f)
}

func mergeFields(fields []map[string]interface{}) map[string]interface{} {
	result := make(map[string]interface{})
	for _, f := range fields {
		for k, v := range f {
			result[k] = v
		}
	}
	return result
}

// Log is kept for backward compatibility.
func Log(message string) {
	fmt.Printf("%s %s\n", time.Now().Format(time.RFC3339), message)
}

package logger

import (
	"bytes"
	"encoding/json"
	"testing"
)

func TestInfoLogsJSON(t *testing.T) {
	var buf bytes.Buffer
	l := New(INFO)
	l.SetOutput(&buf)
	l.Info("server started", map[string]interface{}{"port": 8080})

	var entry map[string]interface{}
	if err := json.Unmarshal(buf.Bytes(), &entry); err != nil {
		t.Fatalf("invalid JSON: %v", err)
	}
	if entry["level"] != "INFO" {
		t.Errorf("expected INFO, got %v", entry["level"])
	}
	if entry["message"] != "server started" {
		t.Errorf("wrong message: %v", entry["message"])
	}
	if entry["port"] != float64(8080) {
		t.Errorf("wrong port: %v", entry["port"])
	}
}

func TestLevelFiltering(t *testing.T) {
	var buf bytes.Buffer
	l := New(WARN)
	l.SetOutput(&buf)
	l.Debug("should not appear")
	l.Info("should not appear")
	l.Warn("warning message")

	if buf.Len() == 0 {
		t.Fatal("expected output for WARN")
	}
	var entry map[string]interface{}
	json.Unmarshal(buf.Bytes(), &entry)
	if entry["level"] != "WARN" {
		t.Errorf("expected WARN, got %v", entry["level"])
	}
}
